1626	\section{Separatedness}
1627	\label{sec:gr_separated}
1628	
1629	\begin{lemma}
1630	[\(\mathrm{Gr}(r,d)\) is separated over \(\mathbb{Z}\)]
1631	  \label{lem:gr_separated}
1632	  \lean{AlgebraicGeometry.Grassmannian.isSeparated}
1633	  \uses{def:gr_glued_scheme, def:gr_transition}
1634	  % SOURCE: [Nitsure], \S 1, sub-section "Separatedness" (read from
1635	  % references/nitsure-hilbert-quot-src/nitsure-hilbert-quot.tex, L856-L860).
1636	  % SOURCE QUOTE:
1637	  % "The intersection of the diagonal of $\grass(r,d)$ with $U^I\times U^J$
1638	  %  can be seen to be the closed subscheme $\Delta_{I,J}\subset U^I\times U^J$
1639	  %  defined by entries of the matrix formula $X^J_I\,X^I - X^J =0$,
1640	  %  and so $\grass(r,d)$ is a separated scheme."
1641	  \textit{Source: [Nitsure], \S 1.}
1642	  The structure morphism \(\mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\)
1643	  (\cref{def:gr_glued_scheme}) is separated; equivalently, the diagonal
1644	  \(\Delta : \mathrm{Gr}(r,d) \to \mathrm{Gr}(r,d) \times_{\mathbb{Z}}
1645	  \mathrm{Gr}(r,d)\) is a closed immersion.
1646	\end{lemma}
1647	
1648	% SOURCE QUOTE PROOF: "The intersection of the diagonal of $\grass(r,d)$ with
1649	% $U^I\times U^J$ can be seen to be the closed subscheme
1650	% $\Delta_{I,J}\subset U^I\times U^J$ defined by entries of the matrix formula
1651	% $X^J_I\,X^I - X^J =0$, and so $\grass(r,d)$ is a separated scheme."
1652	% (references/nitsure-hilbert-quot-src/nitsure-hilbert-quot.tex, L856-L860.)
1653	\begin{proof}
1654	  \uses{def:gr_glued_scheme, def:gr_transition}
1655	  The products \(U^I \times_{\mathbb{Z}} U^J\), as \(I, J\) range over the
1656	  size-\(d\) subsets, form an affine open cover of \(\mathrm{Gr}(r,d)
1657	  \times_{\mathbb{Z}} \mathrm{Gr}(r,d)\). Separatedness may be checked on this
1658	  cover: it suffices to show that for each pair \((I,J)\) the preimage
1659	  \(\Delta^{-1}(U^I \times_{\mathbb{Z}} U^J)\) maps by a closed immersion into
1660	  \(U^I \times_{\mathbb{Z}} U^J\), i.e.\ that the corresponding ring
1661	  homomorphism is surjective.
1662	
1663	  By \cref{def:gr_glued_scheme} the diagonal preimage is the overlap
1664	  \(\Delta^{-1}(U^I \times_{\mathbb{Z}} U^J) = U^I \cap U^J = U^I_J = \Spec
1665	  \mathbb{Z}[X^I, 1/P^I_J]\). The restricted diagonal corresponds to the ring map
1666	  \[
1667	    \delta_{I,J} : \mathbb{Z}[X^I] \otimes_{\mathbb{Z}} \mathbb{Z}[X^J]
1668	    \longrightarrow \mathbb{Z}[X^I, 1/P^I_J],
1669	    \qquad
1670	    X^I \otimes 1 \mapsto X^I, \quad 1 \otimes X^J \mapsto (X^I_J)^{-1} X^I,
1671	  \]
1672	  the second component being the comorphism \(\theta_{I,J}\) of
1673	  \cref{def:gr_transition} (a point of \(U^I_J\) and its image under
1674	  \(\theta_{I,J}\) are the two coordinates of a point of the diagonal). We claim
1675	  \(\delta_{I,J}\) is surjective. Its image contains all entries of \(X^I\)
1676	  (from the first factor). From the second factor it contains the entries of
1677	  \((X^I_J)^{-1} X^I\); taking the \(I\)-minor of this matrix, and using
1678	  \(X^I_I = 1_{d\times d}\), the image contains the entries of \((X^I_J)^{-1}\),
1679	  and in particular
1680	  \[
1681	    \delta_{I,J}(1 \otimes P^J_I) = \det\bigl((X^I_J)^{-1}\bigr) = 1/P^I_J .
1682	  \]
1683	  Hence \(1/P^I_J\) lies in the image, so the image is all of
1684	  \(\mathbb{Z}[X^I, 1/P^I_J]\) and \(\delta_{I,J}\) is surjective. Concretely the
1685	  closed subscheme \(\Delta_{I,J} \subseteq U^I \times_{\mathbb{Z}} U^J\) is cut
1686	  out by the entries of the matrix relation
1687	  \[
1688	    X^J_I \, X^I - X^J \;=\; 0,
1689	  \]
1690	  which on the diagonal holds because \(X^J = (X^I_J)^{-1} X^I\) forces
1691	  \(X^J_I = (X^I_J)^{-1} X^I_I = (X^I_J)^{-1}\) and therefore \(X^J_I X^I =
1692	  (X^I_J)^{-1} X^I = X^J\). As each restricted diagonal is a closed immersion,
1693	  \(\Delta\) is a closed immersion and \(\mathrm{Gr}(r,d)\) is separated over
1694	  \(\mathbb{Z}\).
1695	\end{proof}
